class Solution:
    def countMaxOrSubsets(self, nums):
        n = len(nums)
        best = 0
        cnt = 0

        def dfs(i, cur):
            nonlocal best, cnt
            if i == n:
                if cur == 0:
                    return
                if cur > best:
                    best = cur
                    cnt = 1
                elif cur == best:
                    cnt += 1
                return
            dfs(i + 1, cur)
            dfs(i + 1, cur | nums[i])

        dfs(0, 0)
        return cnt

