class Solution:
    def countMaxOrSubsets(self, nums):
        n = len(nums)
        max_or = 0
        for x in nums:
            max_or |= x
        count = 0
        for mask in range(1, 1 << n):
            cur = 0
            m = mask
            idx = 0
            while m:
                if m & 1:
                    cur |= nums[idx]
                m >>= 1
                idx += 1
            if cur == max_or:
                count += 1
        return count

