var countMaxOrSubsets = function(nums) {
    const n = nums.length;
    let maxOr = 0;
    for (const x of nums) maxOr |= x;
    let count = 0;
    for (let mask = 1; mask < (1 << n); mask++) {
        let cur = 0;
        for (let idx = 0; idx < n; idx++) {
            if (mask & (1 << idx)) cur |= nums[idx];
        }
        if (cur === maxOr) count++;
    }
    return count;
};
